/* fvorbis_rename.h -- symbol namespacing for the vendored decode-only float
 * libvorbis.  Tremor (the int16 default decoder) exports the same public and
 * internal symbol names (ov_*, vorbis_*, mdct_*, floor*_exportbundle, ...), so
 * the two cannot be linked into one binary unrenamed.  This header is force-
 * included (-include) into every vendored libvorbis TU AND the float wrapper,
 * prefixing each libvorbis-defined symbol with fv_ so it links alongside an
 * untouched Tremor.  Shared libogg symbols (ogg_*, oggpack_*) are deliberately
 * NOT renamed -- both decoders resolve them against the single vendored libogg.
 * Generated from nm of the decode object set; do not edit by hand. */
